import{_ as a,c as i,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Funciones de la Plataforma: Modelos y Cuotas | opencode-antigravity-auth","description":"Conozca los tipos de modelos y el sistema de doble cuota de Antigravity Auth. Domine la selección de modelos, configuración de Thinking y Google Search para optimizar el uso de cuotas.","frontmatter":{"title":"Funciones de la Plataforma: Modelos y Cuotas | opencode-antigravity-auth","sidebarTitle":"Desbloquear el Sistema de Doble Cuota","subtitle":"Funciones de la Plataforma: Modelos y Cuotas","description":"Conozca los tipos de modelos y el sistema de doble cuota de Antigravity Auth. Domine la selección de modelos, configuración de Thinking y Google Search para optimizar el uso de cuotas.","order":2},"headers":[],"relativePath":"es/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"es/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),t={name:"es/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function s(n,e,r,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="funciones-de-la-plataforma" tabindex="-1">Funciones de la Plataforma <a class="header-anchor" href="#funciones-de-la-plataforma" aria-label="Permalink to &quot;Funciones de la Plataforma&quot;">​</a></h1><p>Este capítulo te ayuda a comprender profundamente los modelos compatibles con el complemento Antigravity Auth, el sistema de cuotas y las características de la plataforma. Aprenderás a seleccionar el modelo adecuado, configurar la capacidad de Thinking, habilitar Google Search y maximizar la utilización de cuotas.</p><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de comenzar, confirma</p><p>Antes de estudiar este capítulo, asegúrate de haber completado:</p><ul><li><a href="./../start/quick-install/">Instalación Rápida</a>: Completa la instalación del complemento y la primera autenticación</li><li><a href="./../start/first-request/">Primera Solicitud</a>: Realiza con éxito la primera solicitud al modelo</li></ul></div><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><p>Sigue el siguiente orden para dominar progresivamente las funciones de la plataforma:</p><h3 id="_1-modelos-disponibles" tabindex="-1">1. <a href="./available-models/">Modelos Disponibles</a> <a class="header-anchor" href="#_1-modelos-disponibles" aria-label="Permalink to &quot;1. [Modelos Disponibles](./available-models/)&quot;">​</a></h3><p>Conoce todos los modelos disponibles y sus configuraciones de variantes</p><ul><li>Familiarízate con Claude Opus 4.5, Sonnet 4.5 y Gemini 3 Pro/Flash</li><li>Comprende la distribución de modelos entre los dos grupos de cuotas de Antigravity y Gemini CLI</li><li>Domina el uso del parámetro <code>--variant</code></li></ul><h3 id="_2-sistema-de-doble-cuota" tabindex="-1">2. <a href="./dual-quota-system/">Sistema de Doble Cuota</a> <a class="header-anchor" href="#_2-sistema-de-doble-cuota" aria-label="Permalink to &quot;2. [Sistema de Doble Cuota](./dual-quota-system/)&quot;">​</a></h3><p>Comprende el funcionamiento del sistema de doble cuota de Antigravity y Gemini CLI</p><ul><li>Aprende cómo cada cuenta tiene dos grupos independientes de cuotas de Gemini</li><li>Habilita la configuración de fallback automático para duplicar las cuotas</li><li>Especifica explícitamente el uso de grupos de cuotas para modelos específicos</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Habilita Google Search para los modelos de Gemini y mejora la precisión factual</p><ul><li>Permite que Gemini busque información en tiempo real en la web</li><li>Ajusta el umbral de búsqueda para controlar la frecuencia de búsquedas</li><li>Selecciona la configuración adecuada según los requisitos de la tarea</li></ul><h3 id="_4-modelos-thinking" tabindex="-1">4. <a href="./thinking-models/">Modelos Thinking</a> <a class="header-anchor" href="#_4-modelos-thinking" aria-label="Permalink to &quot;4. [Modelos Thinking](./thinking-models/)&quot;">​</a></h3><p>Domina la configuración y el uso de los modelos Thinking de Claude y Gemini 3</p><ul><li>Configura el presupuesto de thinking de Claude</li><li>Utiliza los niveles de thinking de Gemini 3 (minimal/low/medium/high)</li><li>Comprende las estrategias de interleaved thinking y retención de bloques de pensamiento</li></ul><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar aprendiendo:</p><ul><li><a href="./../advanced/multi-account-setup/">Configuración Multi-Cuenta</a>: Configura múltiples cuentas de Google para lograr la agrupación de cuotas y el balanceo de carga</li><li><a href="./../advanced/account-selection-strategies/">Estrategias de Selección de Cuentas</a>: Domina las mejores prácticas de las tres estrategias: sticky, round-robin y hybrid</li><li><a href="./../advanced/configuration-guide/">Guía de Configuración</a>: Domina todas las opciones de configuración y personaliza el comportamiento del complemento según tus necesidades</li></ul>',21)])])}const h=a(t,[["render",s]]);export{p as __pageData,h as default};
